		fmt.Print(pterm.LightGreen("Assistant ▸ "))
		fmt.Println()
		pterm.DefaultParagraph.Println(result.Answer)
		fmt.Println()

		// Append to history
		history = append(history, models.QAHistory{
			Question: line,
