				title := toTitle(slug)
				data, readErr := os.ReadFile(filepath.Join(wikiDir, name))
				if readErr != nil {
					continue
				}
				content := strings.TrimSpace(string(data))
				fmt.Fprintf(&sb, "### %s\n\n%s\n\n---\n\n", title, content)
				pageCount++
			}
		}
		if pageCount == 0 {
			sb.WriteString("*No wiki pag

inue
				}
				content := strings.TrimSpace(string(data))
				fmt.Fprintf(&sb, "### %s\n\n%s\n\n---\n\n", title, content)
