			}
		}
		if pageCount == 0 {
			sb.WriteString("*No wiki pages found. Run `rekipedia scan` first.*\n\n")
		}

		// Truncate to max tokens
		maxChars := contextFlags.maxTokens * 4
		full := sb.String()
