			notice := fmt.Sprintf("\n\n---\n*Context truncated to %d tokens (%d chars). Total available: %d chars.*\n",
				contextFlags.maxTokens, maxChars, len(full))
			full = full[:maxChars-len(notice)] + notice
		}

		// Write output
