	symFile, _ := s["file"].(string)
	if symFile == "" {
		symFile, _ = s["source_file"].(string)
	}
	if symFile == "" {
		return false
	}
	for _, cf := range changedFiles {
		if strings.HasSuffix(symFile, cf) || strings.HasSuffix(cf, symFile) {
