			issues = append(issues, RefactorIssue{
				Kind:     "high_fan_in",
				Symbol:   name,
				File:     symFile[name],
				Severity: "medium",
				Metrics:  map[string]interface{}{"in_degree": count},
				Callers:  callers,
			})
		}
	}
	return issues
}

