snapper := NewSnapshotter(repoRoot, nil, opts.Languages)
currentFiles, err := snapper.Snapshot()
if err != nil {
	return fmt.Errorf("snapshot: %w", err)
}

// ── 3. Diff against stored hashes ──────────────────────────────────────
storedFiles, err := store.GetSnapshot(lastRunID)
if err != nil {
