		bucket = append(bucket, f)
		bucketTokens += fileTokens
	}
	if len(bucket) > 0 {
		shards = append(shards, makeShard(groupDir, bucketIdx, bucket))
	}
	return shards
}

func makeShard(groupDir string, idx int, files []models.FileManifest) models.Shard {
	id := groupDir
	if idx > 0 {
		id = groupDir + "#" + string(rune('0'+idx))
	}
	return models.Shard{
		ShardID: id,
		Root:    groupDir,
		Files:   files,
	}
}

func topLevelDir(path string) string {
	path = filepath.ToSlash(path)
	parts := strings.SplitN(path, "/", 2)
	if len(parts) > 1 {
		return parts[0]
	}
	return "."
}

func fileTokenEstimate(sizeBytes int64) int {
	tokens := int(sizeBytes) / bytesPerToken
	if tokens < 1 {
		return 1
	}
	return tokens
}

, extraIgnore []string, languages []string) *Snapshotter {
	all := append(defaultIgnore, extraIgnore...)
	dirs := make(map[string]bool)
	var globs []string
	for _, pat := range all {
		if !strings.Contains(pat, "*") && !strings.Contains(pat, "/") {
			dirs[pat] = true
		} else {
			globs = append(globs, pat)
		}
	}
	var langSet map[string]bool
	if len(languages) > 0 {
		langSet = make(map[string]bool, len(languages))
		for _, l := range languages {
			langSet[strings.ToLower(l)] = true
		}
	}
	return &Snapshotter{root: root, ignoreGlobs: globs, ignoreDirs: dirs, languages: langSet}
}

// Snapshot walks the repository and returns all relevant files.
func (s *Snapshotter) Snapshot() ([]models.FileManifest, error) {
	var manifests []models.FileManifest

	err := filepath.WalkDir(s.root, func(path string, d os.DirEntry, err error) error {
		if err != nil {
			return nil // skip unreadable entries
		}

		rel, _ := filepath.Rel(s.root, path)
		rel = filepath.ToSlash(rel)

		if d.IsDir() {
			// Never skip the root itself (path == s.root or rel == ".")
			if path == s.root || rel == "." {
				return nil
			}
			base := d.Name()
			if s.ignoreDirs[base] || strings.HasPrefix(base, ".") {
				return filepath.SkipDir
			}
			return nil
		}

		// Check glob patterns
		base := filepath.Base(path)
		for _, glob := range s.ignoreGlobs {
			if matched, _ := filepath.Match(glob, base); matched {
				return nil
			}
		}

		info, err := d.Info()
		if err != nil {
			return nil
		}
		if info.Size() == 0 {
			return nil
		}

		hash, err := sha256File(path)
		if err != nil {
			return nil
		}

		lang := detectLanguage(path)
		if s.languages != nil && !s.languages[lang] {
			return nil
		}
		manifests = append(manifests, models.FileManifest{
			Path:      rel,
			SHA256:    hash,
			SizeBytes: info.Size(),
			Language:  lang,
		})
		return nil
	})

	return manifests, err
}

func sha256File(path string) (string, error) {
	f, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer f

