			Language:  lang,
		})
		return nil
	})

	return manifests, err
}

func sha256File(path string) (string, error) {
	f, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer f.Close()
	h := sha256.New()
	if _, err := io.Copy(h, f); err != nil {
		return "", err
	}
	return hex.EncodeToString(h.Sum(nil)), nil
}

func detectLanguage(path string) string {
	base := strings.ToLower(filepath.Base(path))
	if base == "dockerfile" {
		return "docker"
	}
	ext := strings.ToLower(filepath.Ext(path))
	if lang, ok := languageMap[ext]; ok {
		return lang
	}
	return ""
}

// Package rag provides file chunking, embedding, and vector search for rekipedia.
package rag

import (
	"fmt"
	"path/filepath"
	"strings"
)

// Chunk represents a text segment from a file.
type Chunk struct {
	ID        string `json:"id"`
	FilePath  string `json:"file_path"`
	StartLine string `json:"start_line"`
	EndLine   string `json:"end_line"`
	Text      string `json:"text"`
}

var codeExts = map[string]bool{
	".py": true, ".ts": true, ".tsx": true, ".js": true, ".jsx": true,
	".go": true, ".rs": true, ".java": true, ".kt": true, ".rb": true,
	".swift": true, ".cs": true, ".cpp": true, ".c": true, ".h": true,
	".html": true, ".css": true, ".scss": true,
}

var docExts = map[string]bool{
	".md": true, ".txt": true, ".rst": true, ".yaml": true, ".yml": true,
	".toml": true, ".json": true,
}

const (
	chunkSize    = 2000
	chunkOverlap = 200
	maxCodeSize  = 320000
	maxDocSize   = 32000
)

// ChunkFile splits a file's content into overlapping chunks.
// Returns nil if the file should be skipped.
func ChunkFile(path, content string) []Chunk {
	ext := strings.ToLower(filepath.Ext(path))
	isCode := codeExts[ext]
	isDoc := docExts[ext]

	if !isCode && !isDoc {
		return nil
	}

	maxSize := maxCodeSize
	if isDoc {
		maxSize = maxDocSize
	}
	if len(content) > maxSize {
		return nil
	}

	lines := strings.Split(content, "\n")

	var chunks []Chunk
	runes := []rune(content)
	total := len(runes)
	idx := 0
	chunkIdx := 0

	for idx < total {
		end := idx + chunkSize
		if end > total {
			end = total
		}
		text := string(runes[idx:end])

		// Compute start/end line numbers
		startLine := countLines(string(runes[:idx]), lines)
		endLine := startLine + strings.Count(text, "\n")

		chunks = append(chunks, Chunk{
			ID:        fmt.Sprintf("%s#%d", path, chunkIdx),
			FilePath:  path,
			StartLine: fmt.Sprintf("%d", startLine+1),
			EndLine:   fmt.Sprintf("%d", endLine+1),
			Text:      text,
		})
		chunkIdx++

		if end == total {
			break
		}
		idx += chunkSize - chunkOverlap
	}

	re

StartLine: fmt.Sprintf("%d", startLine+1),
			EndLine:   fmt.Sprintf("%d", endLine+1),
			Text:      text,
		})
		chunkIdx++

		if end == total {
			break
		}
		idx += chunkSize - chunkOverlap
	}

	return chunks
}

func countLines(before string, _ []string) int {
	return strings.Count(before, "\n")
}

package rag

import (
	"context"
	"fmt"
	"os"
	"path/filepath"

	"github.com/unrealandychan/rekipedia/internal/llm"
	"github.com/unrealandychan/rekipedia/internal/models"
	"github.com/unrealandychan/rekipedia/pkg/fsutil"
)

// EmbedPipeline builds and queries a vector index for a repository.
type EmbedPipeline struct {
	outputDir string
	llmClient *llm.Client
}

// NewEmbedPipeline creates an EmbedPipeline.
func NewEmbedPipeline(outputDir string, cfg models.LLMConfig) *EmbedPipeline {
	return &EmbedPipeline{
		outputDir: outputDir,
		llmClient: llm.New(cfg),
	}
}

// Build walks repoRoot, chunks files, embeds in batches, and saves the VectorStore.
// Returns the total number of chunks embedded.
func (e *EmbedPipeline) Build(repoRoot string, progress func(string)) (int, error) {
	log := func(msg string) {
		if progress != nil {
			progress(msg)
		}
	}

	// Walk repo
	fileInfos, err := fsutil.WalkRepo(repoRoot, nil)
	if err != nil {
		return 0, fmt.Errorf("walk repo: %w", err)
	}

	var chunks []Chunk
	for _, fi := range fileInfos {
		data, err := os.ReadFile(fi.AbsPath)
		if err != nil {
			continue
		}
		cs := ChunkFile(fi.Path, string(data))
		chunks = append(chunks, cs...)
	}
	log(fmt.Sprintf("Chunked %d files → %d chunks", len(fileInfos), len(chunks)))

	store := NewVectorStore()
	batchSize := 100
	ctx := context.Background()

	for i := 0; i < len(chunks); i += batchSize {
		end := i + batchSize
		if end > len(chunks) {
			end = len(chunks)
		}
		batch := chunks[i:end]
		texts := make([]string, len(batch))
		for j, c := range batch {
			texts[j] = c.Text
		}
		embeddings, err := e.llmClient.Embed(ctx, texts)
		if err != nil {
			return 0, fmt.Errorf("embed batch %d: %w", i/batchSize, err)
		}
		for j, emb := range embeddings {
			store.Add(batch[j], emb)
		}
		log(fmt.Sprintf("Embedded %d/%d chunks", min(i+batchSize, len(chunks)), len(chunks)))
	}

	storeDir := filepath.Join(e.outputDir, "vectors")
	if err := store.Save(storeDir); err != nil {
		return 0, fmt.Erro

.Sprintf("Embedded %d/%d chunks", min(i+batchSize, len(chunks)), len(chunks)))
	}

	storeDir := filepath.Join(e.outputDir, "vectors")
	if err := store.Save(storeDir); err != nil {
		return 0, fmt.Errorf("save vector store: %w", err)
	}
	log(fmt.Sprintf("Vector store saved to %s", storeDir))
	return len(chunks), nil
}

// Search embeds the query and returns the top-K results from the vector store.
func (e *EmbedPipeline) Search(query string, topK int) ([]SearchResult, error) {
	storeDir := filepath.Join(e.outputDir, "vectors")
	store := NewVectorStore()
	if err := store.Load(storeDir); err != nil {
		return nil, fmt.Errorf("load vector store: %w", err)
	}
	ctx := context.Background()
	embeddings, err := e.llmClient.Embed(ctx, []string{query})
	if err != nil {
		return nil, fmt.Errorf("embed query: %w", err)
	}
	if len(embeddings) == 0 {
		return nil, fmt.Errorf("no embedding returned")
	}
	return store.Search(embeddings[0], topK), nil
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

