}

function escHtml(t){return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}

function fmtTs(ts){
  if(!ts) return '';
  try { return new Date(ts).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}); } catch{ return ts.substring(0,16).replace('T',' '); }
}

let isStreaming = false;

async function loadHistory() {
  try {
    const resp = await fetch('/api/history');
    if (!resp.ok) return;
    const history = await resp.json();
    if (!history || history.length === 0) return;
    document.getElementById('empty-state')?.remove();
    for (const item of history) {
      appendMessage('user', item.question, item.created_at || '');
      appendMessage('assistant', item.answer, item.created_at || '');
    }
    scrollChat();
  } catch(e) { console.warn('history load failed', e); }
}

function appendMessage(role, text, ts) {
  const hist = document.getElementById('chat-history');
  const msg = document.createElement('div');
  msg.className = 'msg ' + role;
  msg.innerHTML = `
    <div class="bubble">${role === 'assistant' ? renderMd(text) : escHtml(text)}</div>
    <div class="meta">${role === 'user' ? 'You' : 'Assistant'}${ts ? ' · ' + fmtTs(ts) : ''}</div>
  `;
  hist.appendChild(msg);
  return msg;
}

