function scrollChat(){
  const h=document.getElementById('chat-history');
  h.scrollTop=h.scrollHeight;
}

async function sendQuestion() {
  if (isStreaming) return;
  const input = document.getElementById('ask-input');
  const q = input.value.trim();
  if (!q) return;

  document.getElementById('empty-state')?.remove();
  input.value = '';
  input.style.height = '';

  appendMessage('user', q, new Date().toISOString());

  const hist = document.getElementById('chat-history');
  const assistantMsg = document.createElement('div');
  assistantMsg.className = 'msg assistant';
  assistantMsg.innerHTML = '<div class="bubble thinking">Thinking…</div><div class="meta">Assistant</div>';
  hist.appendChild(assistantMsg);
  scrollChat();

  const bubble = assistantMsg.querySelector('.bubble');
  let accumulated = '';
  isStreaming = true;
  document.getElementById('ask-send').disabled = true;

  try {
    const resp = await fetch('/ask/stream', {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({question: q})
    });
    if (!resp.ok || !resp.body) {
      bubble.textContent = 'Error: ' + resp.statusText;
      isStreaming = false;
      document.getElementById('ask-send').disabled = false;
      return;
    }
    const reader = resp.body.getReader();
    const decoder = new TextDecoder();
    let buf = '';
    while (true) {
      const {done, value} = await reader.read();
      if (done) break;
      buf += decoder.decode(value, {stream: true});
      const lines = buf.split('\n');
      buf = lines.pop();
      for (const line of lines) {
        if (!line.startsWith('data: ')) continue;
        const chunk = line.slice(6);
        if (chunk === '[DONE]') { reader.cancel(); break; }
        if (chunk.startsWith('[ERROR]')) { bubble.textContent = chunk; break; }
        accumulated += chunk.

  const chunk = line.slice(6);
        if (chunk === '[DONE]') { reader.cancel(); break; }
        if (chunk.startsWith('[ERROR]')) { bubble.textContent = chunk; break; }
        accumulated += chunk.replace(/\\n/g, '\n');
        bubble.className = 'bubble';
        bubble.innerHTML = renderMd(accumulated);
        scrollChat();
      }
    }
  } catch(e) {
    bubble.textContent = 'Stream error: ' + e.message;
  }

  isStreaming = false;
  document.getElementById('ask-send').disabled = false;
}

function clearChat() {
  const hist = document.getElementById('chat-history');
  hist.innerHTML = '<div id="empty-state" style="flex:1;display:flex;align-items:center;justify-content:center;color:#374151;font-size:14px;text-align:center">No conversation yet.<br>Ask your first question below.</div>';
