<script>
  function toggleCat(el) { el.classList.toggle('collapsed'); }

  const searchInput = document.getElementById('wiki-search');
  const wikiNav    = document.getElementById('wiki-nav');
  const searchRes  = document.getElementById('wiki-search-results');
  let searchTimer  = null;

  if (searchInput) {
    searchInput.addEventListener('input', function() {
      const q = this.value.trim();
      clearTimeout(searchTimer);
      if (!q || q.length < 2) {
        if (wikiNav) wikiNav.style.display = '';
        if (searchRes) { searchRes.innerHTML = ''; searchRes.classList.remove('visible'); }
        return;
      }
      searchTimer = setTimeout(() => {
        fetch('/api/wiki/search?q=' + encodeURIComponent(q))
          .then(r => r.json())
          .then(items => {
            if (wikiNav) wikiNav.style.display = 'none';
            if (!searchRes) return;
            if (!items.length) {
              searchRes.innerHTML = '<p class="no-results">No results for "' + q + '"</p>';
            } else {
              searchRes.innerHTML = items.map(item =>
                '<a class="search-result-item" href="/wiki/' + item.slug + '">' +
                '<div class="search-result

            } else {
              searchRes.innerHTML = items.map(item =>
                '<a class="search-result-item" href="/wiki/' + item.slug + '">' +
                '<div class="search-result-title">◦ ' + item.title + '</div>' +
                (item.snippet ? '<div class="search-result-snippet">' + item.snippet + '</div>' : '') +
                '<div class="search-result-section">' + item.section.replace(/[-_]/g,' ') + '</div>' +
                '</a>'
              ).join('');
            }
            searchRes.classList.add('visible');
          })
          .catch(() => {});
      }, 250);
    });

    searchInput.addEventListener('keydown', function(e) {
      if (e.key === 'Escape') {
        this.value = '';
        if (wikiNav) wikiNav.style.display = '';
        if (searchRes) { searchRes.innerHTML = ''; searchRes.classList.remove('visible'); }
      }
    });
  }
</script>
</body>
