const schemaVersion = 1

// Store wraps a SQLite database with high-level operations.
type Store struct {
	db   *sql.DB
	path string
}

// Open opens (or creates) a Store at dbPath.
func Open(dbPath string) (*Store, error) {
	db, err := sql.Open("sqlite", dbPath+"?_journal_mode=WAL&_foreign_keys=on")
	if err != nil {
		return nil, fmt.Errorf("open sqlite: %w", err)
	}
	s := &Store{db: db, path: dbPath}
	if err := s.migrate(); err != nil {
		_ = db.Close()
		return nil, fmt.Errorf("migrate: %w", err)
	}
	return s, nil
}

// DefaultPath returns the standard store path inside a repo's .rekipedia dir.
func DefaultPath(repoRoot string) string {
	return filepath.Join(repoRoot, ".rekipedia", "store.db")
}

// Close closes the underlying database connection.
func (s *Store) Close() error {
	return s.db.Close()
}

// migrate creates tables if they don't exist.
func (s *Store) migrate() error {
	ddl := []string{
		`CREATE TABLE IF NOT EXISTS runs (
			run_id      TEXT PRIMARY KEY,
			repo_path   TEXT NOT NULL,
			started_at  TEXT NOT NULL,
			finished_at TEXT,
			status      TEXT NOT NULL DEFAULT 'running',
			model       TEXT,
			page_count  INTEGER DEFAULT 0
		)`,
		`CREATE TABLE IF NOT EXISTS symbols (
			id         INTEGER PRIMARY KEY AUTOINCREMENT,
			run_id     TEXT NOT NULL,
			name       TEXT NOT NULL,
			kind       TEXT NOT NULL,
			file       TEXT NOT NULL,
			line_start INTEGER,
			line_end   INTEGER,
			signature  TEXT,
			docstring  TEXT
		)`,
		`CREATE TABLE IF NOT EXISTS relationships (
			id       INTEGER PRIMARY KEY AUTOINCREMENT,
			run_id   TEXT NOT NULL,
			from_sym TEXT NOT NULL,
			to_sym   TEXT NOT NULL,
			kind     TEXT NOT NULL,
			file     TEXT
		)`,
		`CREATE TABLE IF NOT EXISTS wiki_pages (
			id           INTEGER PRIMARY KEY

   TEXT NOT NULL,
			from_sym TEXT NOT NULL,
			to_sym   TEXT NOT NULL,
			kind     TEXT NOT NULL,
			file     TEXT
		)`,
		`CREATE TABLE IF NOT EXISTS wiki_pages (
			id           INTEGER PRIMARY KEY AUTOINCREMENT,
			run_id       TEXT NOT NULL,
			slug         TEXT NOT NULL,
			title        TEXT NOT NULL,
			section      TEXT,
			content      TEXT,
			priority     INTEGER DEFAULT 50,
			importance   INTEGER DEFAULT 50,
			generated_at TEXT
		)`,
		`CREATE UNIQUE INDEX IF NOT EXISTS uq_wiki_slug ON wiki_pages(run_id, slug)`,
		`CREATE TABLE IF NOT EXISTS qa_history (
			id        INTEGER PRIMARY KEY AUTOINCREMENT,
			run_id    TEXT,
			question  TEXT NOT NULL,
			answer    TEXT,
			asked_at  TEXT NOT NULL
		)`,
		`CREATE TABLE IF NOT EXISTS file_manifest (
			path       TEXT PRIMARY KEY,
			sha256     TEXT NOT NULL,
			size_bytes INTEGER,
			language   TEXT,
			last_seen  TEXT NOT NULL
		)`,
	}
	for _, stmt := range ddl {
		if _, err := s.db.Exec(stmt); err != nil {
			return fmt.Errorf("ddl %q: %w", stmt[:40], err)
		}
	}
	return nil
}

