function appendUserMsg(text) {
  const escaped = text.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  appendMessage('user', escaped);
}

function appendAIMsg(id) {
  const welcome = document.getElementById('welcome-msg');
  if (welcome) welcome.remove();

  const container = document.getElementById('chat-messages');
  const outer = document.createElement('div');
  outer.className = 'msg msg-ai';
  outer.id = id;

  const bubble = document.createElement('div');
  bubble.className = 'msg-bubble streaming cursor';
  bubble.innerHTML = '<em style="color:var(--muted)">Thinking…</em>';

  outer.appendChild(bubble);
  container.appendChild(outer);
  container.scrollTop = container.scrollHeight;
  return bubble;
}

async function submitQuestion() {
  const input = document.getElementById('q-input');
  const q = input.value.trim();
  if (!q) return;

  const btn = document.getElementById('ask-btn');
  btn.disabled = true;
  input.value = '';
  input.style.height = 'auto';

  appendUserMsg(q);
  const aiId = 'ai-msg-' + (++msgIdCounter);
  const aiBubble = appendAIMsg(aiId);

  let accumulated = '';
  let firstChunk = true;

  try {
    const url = '/ask/stream?question=' + encodeURIComponent(q);
    const es = new EventSource(url);

    es.onmessage = (e) => {
      if (e.data === '[DONE]') {
        es.close();
        btn.disabled = false;
        aiBubble.classList.remove('streaming', 'cursor');
        aiBubble.innerHTML = renderMd(accumulated);
        // Add to history tab
        addToHistoryTab(q, renderMd(accumulated));
        documen

  aiBubble.classList.remove('streaming', 'cursor');
        aiBubble.innerHTML = renderMd(accumulated);
        // Add to history tab
        addToHistoryTab(q, renderMd(accumulated));
        document.getElementById('chat-messages').scrollTop = 999999;
        return;
      }
      if (e.data.startsWith('[ERROR]')) {
        aiBubble.innerHTML = '<span style="color:var(--red)">' + e.data.replace('[ERROR]','').trim() + '</span>';
        aiBubble.classList.remove('streaming', 'cursor');
        es.close(); btn.disabled = false; return;
      }
      const chunk = e.data.replace(/\\n/g, '\n');
      accumulated += chunk;
      if (firstChunk) { firstChunk = false; }
      aiBubble.innerHTML = renderMd(accumulated);
      aiBubble.classList.add('cursor');
      document.getElementById('chat-messages').scrollTop = 999999;
    };

    es.onerror = () => {
      es.close();
      if (!accumulated) {
        aiBubble.innerHTML = '<span style="color:var(--red)">Stream error — check server logs</span>';
      }
      aiBubble.classList.remove('streaming', 'cursor');
      btn.disabled = false;
    };

  } catch(err) {
    aiBubble.innerHTML = '<span style="color:var(--red)">Request failed: ' + err.message + '</span>';
    aiBubble.classList.remove('streaming', 'cursor');
    btn.disabled = false;
  }
}

function addToHistoryTab(question, answerHtml) {
  const list = document.getElementById('history-list');
  // Remove empty state if present
  const empty = list.querySelector('.hist-empty');
  if (empty) empty.remove();

  const now = new Date().toLocaleString();
  const item = document.createElement('div');
  item.className = 'hist-item';
  item.innerHTML = `
    <div class="hist-header" onclick="toggleHist(this.parentElement)">
      <div class="hist-q">${question.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</div>
      <div class="hist-meta">${now}</div>
      <div class="hist-chevron">▶</div>
    </div>
    <div class="hist-answer">${answerHtml}</div>

,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</div>
      <div class="hist-meta">${now}</div>
      <div class="hist-chevron">▶</div>
    </div>
    <div class="hist-answer">${answerHtml}</div>`;
  list.prepend(item);

  // Update badge
  const badge = document.getElementById('history-count');
  badge.textContent = parseInt(badge.textContent || '0') + 1;
}
